patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..537adf8cba27 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1161,9 +1161,23 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
     }
   }

+
+  // fold `div(X, C0) * C1 + rem(X, C0)` to `div(X, C0) * (C1 - C0) + X`
+  if ((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
+      (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) {
+    Value *DivOpV;
+    APInt DivOpC;
+    if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+        C0 == DivOpC) {
+      if (MulOpV->hasOneUse()) {
+        Value *NewMul = Builder.CreateMul(MulOpV, ConstantInt::get(X->getType(), MulOpC - C0));
+        return BinaryOperator::CreateAdd(NewMul, X);
+      }
+    }
+  }
+
   return nullptr;
 }
-
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:

